Hot-Reloading <p>Enable file watching in development builds. Changed assets are reloaded and all handles are updated in-place — entities referencing the asset see the new version immediately.</p> <pre><code>fn configure_asset_hot_reload(asset_server: Res&lt;AssetServer&gt;) {
    #[cfg(debug_assertions)]
    {
        asset_server.watch_for_changes().unwrap();
    }
}
</code></pre>

Asset Preprocessing <p>Precompile assets offline to avoid runtime cost. Bevy supports <code>.meta</code> files for controlling import settings.</p> <pre><code>fn configure_asset_processing(app: &amp;mut App) {
    app.add_plugins(bevy::asset::AssetPlugin {
        mode: bevy::asset::AssetMode::Processed,
        file_path: "assets".to_string(),
        processed_file_path: "imported_assets/Default".to_string(),
        watch_for_changes_override: None,
        ..default()
    });
}
</code></pre>

Asset Lifecycle Management <pre><code>fn unload_unused_assets(
    mut assets: ResMut&lt;Assets&lt;Image&gt;&gt;,
    used_handles: Query&lt;&amp;Handle&lt;Image&gt;&gt;,
) {
    let mut in_use: HashSet&lt;_&gt; = used_handles.iter()
        .map(|h| h.id())
        .collect();

    let to_remove: Vec&lt;_&gt; = assets.iter()
        .filter(|(id, _)| !in_use.contains(id))
        .map(|(id, _)| id)
        .collect();

    for id in to_remove {
        assets.remove(id);
    }
}
</code></pre>

Input <p>Bevy's <code>Input&lt;T&gt;</code> resource tracks key/button/mouse state per frame. <code>just_pressed()</code> and <code>just_released()</code> detect transitions.</p> <pre><code>use bevy::input::ButtonInput;

fn keyboard_input_system(
    keyboard: Res&lt;ButtonInput&lt;KeyCode&gt;&gt;,
    mut query: Query&lt;&amp;mut Transform, With&lt;Player&gt;&gt;,
    time: Res&lt;Time&gt;,
) {
    let Ok(mut transform) = query.get_single_mut() else { return };

    let speed = 10.0;
    let dt = time.delta_secs();

    if keyboard.pressed(KeyCode::KeyW) {
        transform.translation.z -= speed * dt;
    }
    if keyboard.pressed(KeyCode::KeyS) {
        transform.translation.z += speed * dt;
    }
    if keyboard.pressed(KeyCode::KeyA) {
        transform.translation.x -= speed * dt;
    }
    if keyboard.pressed(KeyCode::KeyD) {
        transform.translation.x += speed * dt;
    }

    if keyboard.just_pressed(KeyCode::Space) {
        info!("Jump!");
    }

    if keyboard.just_released(KeyCode::ShiftLeft) {
        info!("Sprint ended");
    }
}
</code></pre>

Input <pre><code>fn gamepad_input_system(
    gamepad_buttons: Res&lt;ButtonInput&lt;GamepadButton&gt;&gt;,
    gamepad_axes: Res&lt;Axis&lt;GamepadAxis&gt;&gt;,
    gamepads: Query&lt;&amp;Gamepad&gt;,
) {
    for gamepad in gamepads.iter() {
        let left_x = gamepad_axes
            .get(GamepadAxis::new(gamepad, GamepadAxisType::LeftStickX))
            .unwrap_or(0.0);

        let left_y = gamepad_axes
            .get(GamepadAxis::new(gamepad, GamepadAxisType::LeftStickY))
            .unwrap_or(0.0);

        let movement = Vec2::new(left_x, left_y);

        if gamepad_buttons.just_pressed(GamepadButton::new(
            gamepad,
            GamepadButtonType::South,
        )) {
            info!("A button pressed on gamepad {:?}", gamepad);
        }
    }
}
</code></pre>

leafwing-input-manager Action Mapping <p><code>leafwing-input-manager</code> decouples input devices from game actions. "Jump" can be bound to Space, Gamepad South, or touch — the system only cares about <code>ActionState::just_pressed(Action::Jump)</code>.</p> <pre><code>use leafwing_input_manager::{
    prelude::*,
    Actionlike,
    InputManagerBundle,
};

#[derive(Actionlike, PartialEq, Eq, Hash, Clone, Copy, Debug, Reflect)]
enum PlayerAction {
    Move,
    Jump,
    Shoot,
    Interact,
    Pause,
}

fn setup_input_mapping(mut commands: Commands) {
    let input_map = InputMap::new([
        (KeyCode::Space, PlayerAction::Jump),
        (KeyCode::KeyW, PlayerAction::Move),
        (KeyCode::KeyA, PlayerAction::Move),
        (KeyCode::KeyS, PlayerAction::Move),
        (KeyCode::KeyD, PlayerAction::Move),
        (MouseButton::Left, PlayerAction::Shoot),
        (KeyCode::KeyE, PlayerAction::Interact),
        (KeyCode::Escape, PlayerAction::Pause),
        (GamepadButtonType::South, PlayerAction::Jump),
        (GamepadButtonType::RightTrigger2, PlayerAction::Shoot),
        (GamepadButtonType::Start, PlayerAction::Pause),
    ])
    .with_dual_axis_stick(
        GamepadStick::LEFT,
        VirtualDPad::wasd(
            KeyCode::KeyW,
            KeyCode::KeyS,
            KeyCode::KeyA,
            KeyCode::KeyD,
        ),
        PlayerAction::Move,
    );

    commands.spawn(InputManagerBundle::&lt;PlayerAction&gt; {
        action_state: ActionState::default(),
        input_map,
    });
}

fn action_driven_movement(
    query: Query&lt;&amp;ActionState&lt;PlayerAction&gt;&gt;,
    mut transform_query: Query&lt;&amp;mut Transform&gt;,
) {
    let action_state = query.single();

    if action_state.just_pressed(&amp;PlayerAction::Jump) {
        info!("Player jumped via action mapping");
    }

    if action_state.pressed(&amp;PlayerAction::Shoot) {
        info!("Shooting!");
    }

    let axis_pair = action_state
        .clamped_axis_pair(&amp;PlayerAction::Move)
        .unwrap_or_default();

    for mut transform in transform_query.iter_mut() {
        transform.translation.x += axis_pair.x() * 0.1;
        transform.translation.z -= axis_pair.y() * 0.1;
    }
}
</code></pre>

Input Buffering &amp; Fixed Timestep <p>Input must be collected in <code>Update</code> but processed in <code>FixedUpdate</code>. This prevents one fast frame from triggering multiple actions and ensures deterministic input handling.</p> <pre><code>#[derive(Resource, Default)]
struct InputBuffer {
    actions: Vec&lt;BufferedAction&gt;,
}

#[derive(Clone)]
enum BufferedAction {
    Jump,
    Shoot,
    Interact,
}

fn collect_input(
    keyboard: Res&lt;ButtonInput&lt;KeyCode&gt;&gt;,
    mut input_buffer: ResMut&lt;InputBuffer&gt;,
) {
    input_buffer.actions.clear();

    if keyboard.just_pressed(KeyCode::Space) {
        input_buffer.actions.push(BufferedAction::Jump);
    }
    // Note: MouseButton input requires a separate ButtonInput&lt;MouseButton&gt; resource.
    // This example assumes a combined input mapping for illustration.
    if mouse.just_pressed(MouseButton::Left) {
        input_buffer.actions.push(BufferedAction::Shoot);
    }
    if keyboard.just_pressed(KeyCode::KeyE) {
        input_buffer.actions.push(BufferedAction::Interact);
    }
}

fn process_input_in_fixed_update(
    mut input_buffer: ResMut&lt;InputBuffer&gt;,
    mut commands: Commands,
) {
    for action in input_buffer.actions.drain(..) {
        match action {
            BufferedAction::Jump =&gt; { /* apply jump */ }
            BufferedAction::Shoot =&gt; { /* spawn projectile */ }
            BufferedAction::Interact =&gt; { /* interact with nearest */ }
        }
    }
}
</code></pre>

